#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007ULL

static unsigned long long mod_pow(unsigned long long base, unsigned long long exp) {
    unsigned long long res = 1ULL;
    base %= MOD;
    while (exp) {
        if (exp & 1ULL) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1ULL;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long N;
        scanf("%llu", &N);
        int k = __builtin_popcountll(N);
        unsigned long long pow3 = mod_pow(3ULL, k);
        unsigned long long pow2 = mod_pow(2ULL, k);
        unsigned long long ans = (pow3 + MOD - (3ULL * pow2) % MOD + 3ULL) % MOD;
        printf("%llu\n", ans);
    }
    return 0;
}

