#include <bits/stdc++.h>
using namespace std;
const long long MOD = 1000000007LL;

long long mod_pow(long long base, long long exp) {
    long long res = 1 % MOD;
    base %= MOD;
    while (exp) {
        if (exp & 1) res = res * base % MOD;
        base = base * base % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        unsigned long long N; cin >> N;
        int k = __builtin_popcountll(N);
        long long pow3 = mod_pow(3, k);
        long long pow2 = mod_pow(2, k);
        long long ans = (pow3 - 3LL * pow2 % MOD + 3LL) % MOD;
        if (ans < 0) ans += MOD;
        cout << ans << '\n';
    }
    return 0;
}

