function modPow(base, exp) {
  base = BigInt(base) % MOD;
  let result = 1n;
  let e = BigInt(exp);
  while (e > 0n) {
    if (e & 1n) result = (result * base) % MOD;
    base = (base * base) % MOD;
    e >>= 1n;
  }
  return result;
